using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new[]
            {
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
                new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var instructors = new[]
            {
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") }
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            // Add enrollments
            var studentIds = new List<int>();
            foreach (var s in context.Students)
                studentIds.Add(s.ID);

            if (studentIds.Count > 0)
            {
                context.Enrollments.Add(new Enrollment { StudentID = studentIds[0], CourseID = 1050, Grade = Grade.A });
                context.Enrollments.Add(new Enrollment { StudentID = studentIds[0], CourseID = 4022, Grade = Grade.C });
                context.Enrollments.Add(new Enrollment { StudentID = studentIds[1], CourseID = 1045, Grade = Grade.B });
                context.SaveChanges();
            }

            // Add office assignment
            var instrIds = new List<int>();
            foreach (var i in context.Instructors)
                instrIds.Add(i.ID);

            if (instrIds.Count > 0)
            {
                context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instrIds[0], Location = "Smith 17" });

                context.CourseAssignments.Add(new CourseAssignment { InstructorID = instrIds[0], CourseID = 1050 });
                context.CourseAssignments.Add(new CourseAssignment { InstructorID = instrIds[1], CourseID = 1045 });
                context.SaveChanges();
            }
        }

        /// <summary>
        /// Drain the static NotificationService queue to ensure test isolation
        /// </summary>
        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 5);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_SetsTotalPagesCorrectly()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 3);

            // Ceiling(10/3) = 4
            Assert.Equal(4, list.TotalPages);
        }

        [Theory]
        [InlineData(10, 5, 2)]
        [InlineData(10, 10, 1)]
        [InlineData(11, 5, 3)]
        [InlineData(1, 5, 1)]
        [InlineData(0, 5, 0)]
        public void Constructor_TotalPages_CeilingDivision(int count, int pageSize, int expectedTotalPages)
        {
            var items = new List<int>();
            var list = new PaginatedList<int>(items, count, 1, pageSize);

            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 10);

            Assert.Equal(3, list.Count);
            Assert.Equal("a", list[0]);
            Assert.Equal("b", list[1]);
            Assert.Equal("c", list[2]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPageOfMultiple_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_OnlyPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(2, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_PageSizeMatchesCount_SinglePage()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

