+                context.CourseAssignments.Add(new CourseAssignment { InstructorID = instrIds[0], CourseID = 1050 });
+                context.CourseAssignments.Add(new CourseAssignment { InstructorID = instrIds[1], CourseID = 1045 });
+                context.SaveChanges();
+            }
+        }
+
+        /// <summary>
+        /// Drain the static NotificationService queue to ensure test isolation
+        /// </summary>
+        public static void DrainNotificationQueue()
+        {
+            var service = new NotificationService();
+            while (service.ReceiveNotification() != null) { }
+        }
+    }
+}
