using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            TestHelper.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
            // Verify ascending order by LastName
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) <= 0);
            }
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) >= 0);
            }
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate <= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate >= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Meredith", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            // Add more students to need pagination (page size = 10)
            for (int i = 0; i < 12; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"First{i}",
                    LastName = $"Last{i:D3}",
                    EnrollmentDate = DateTime.Parse("2023-01-01")
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(2, model.PageIndex);
            Assert.True(model.HasPreviousPage);
        }

