            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_OutOfRangeDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Edit(studentId) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(studentId, student.ID);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_UpdatesAndRedirects()
        {
            var existingStudent = _context.Students.First();
            // Detach to avoid tracking conflicts
            _context.Entry(existingStudent).State = EntityState.Detached;

            var student = new Student
            {
                ID = existingStudent.ID,
                FirstMidName = "Updated",
                LastName = "Name",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Delete(studentId) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(studentId, student.ID);
        }

