            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_NonExistentId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999) as NotFoundResult;

            Assert.NotNull(result);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var student = _context.Students.First();
            var studentId = student.ID;

            var result = _controller.DeleteConfirmed(studentId) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Students.Find(studentId));
        }

        #endregion
    }
