        public NotificationsControllerTests()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            TestHelper.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            service.SendNotification("Course", "100", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var jsonResult = result as JsonResult;
            Assert.NotNull(jsonResult);
            Assert.NotNull(jsonResult.Value);

            // Check the anonymous object's properties
            dynamic value = jsonResult.Value!;
            var type = value.GetType();
            var successProp = type.GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var jsonResult = result as JsonResult;
            Assert.NotNull(jsonResult);

            dynamic value = jsonResult.Value!;
            var type = value.GetType();
            var countProp = type.GetProperty("count");
            Assert.NotNull(countProp);
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsTo10Notifications()
        {
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var jsonResult = result as JsonResult;
            Assert.NotNull(jsonResult);

            dynamic value = jsonResult.Value!;
            var type = value.GetType();
            var countProp = type.GetProperty("count");
            Assert.NotNull(countProp);
            Assert.Equal(10, (int)countProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var jsonResult = result as JsonResult;
            Assert.NotNull(jsonResult);

            dynamic value = jsonResult.Value!;
            var type = value.GetType();
            var successProp = type.GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }
    }
}

