+            service.SendNotification("Course", "100", "Math", EntityOperation.UPDATE);
+
+            var result = _controller.GetNotifications();
+
+            Assert.NotNull(result);
+            var jsonResult = result as JsonResult;
+            Assert.NotNull(jsonResult);
+            Assert.NotNull(jsonResult.Value);
+
+            // Check the anonymous object's properties
+            dynamic value = jsonResult.Value!;
+            var type = value.GetType();
+            var successProp = type.GetProperty("success");
+            Assert.NotNull(successProp);
+            Assert.True((bool)successProp.GetValue(value));
+        }
